13	
14	  // Base premiums for main items (with processing fee)
15	  it.todo("single plain sword (steel, enchantment 0) → premium 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion → premium 45 G (40 base + 5 fee)");
19	
20	  // Component pricing
21	  it.todo("2 runes → 55 G premium (50 base + 5 fee)");
22	  it.todo("3 runes → 65 G premium (60 base block + 5 fee)");
23	  it.todo("4 runes → 105 G premium (100 base + 5 fee, no block)");
24	  it.todo("7 runes → 180 G premium (175 base + 5 fee)");
25	  it.todo("2 runes + 1 moonstone → 80 G premium (75 base, no block since different types)");
26	  it.todo("3 runes + 3 moonstones → 125 G premium (120 base, two separate blocks)");
27	
28	  // Item-specific modifiers (cursed, high enchantment)
29	  it.todo("cursed sword (enchantment 3) → curse surcharge 50%: 100 + 50 + 5 = 155 G");
30	  it.todo("sword with enchantment 5 → high-enchant surcharge 30%: 100 + 30 + 5 = 135 G");
31	  it.todo("sword with enchantment 4 → no high-enchant surcharge: 100 + 5 = 105 G");
32	  it.todo("cursed sword with enchantment 5 → both surcharges: 100 + 50 + 30 + 5 = 185 G");
33	
34	  // Policy-wide modifiers
35	  it.todo("customer with 2 years → loyalty discount 20% applies");
36	  it.todo("customer with 0 years → no loyalty discount");
37	
38	  // Modifier scope on multi-item policies
39	  it.todo("cursed sword + plain amulet → curse applies to sword only: 100+60+50+5 = 215 G");
40	
41	  // First insurance surcharge
42	  it.todo("first insurance per item: +10% per item base premium");
43	
44	  // Follow-up contract discount
45	  it.todo("second quote gets 15% follow-up discount on policy base");
46	
47	  // Rounding
48	  it.todo("premium 197.5 G → rounded up to 198 G (in MHPCO's favor)");
49	
50	  // Integration examples
51	  it.todo("newcomer with cursed sword (steel, enchantment 3): 0 years, first contract → premium 165 G");
52	  it.todo("long-standing customer's 2nd contract: cursed sword enchant 7, 3 years → premium 160 G");
53	
54	  // Claim: standard reimbursement
