56	  it.todo("claim on rune, damage 200 G → payout 100 G (no special clause)");
57	
58	  // Claim: enchantment threshold
59	  it.todo("claim on steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
60	
61	  // Claim: dragon material
62	  it.todo("claim on dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
63	  it.todo("claim on dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
64	  it.todo("claim on dragon sword, enchantment 8, damage 1000 G → payout 400 G (high-enchant clause applies)");
65	
66	  // Claim: deductible per damage event
67	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
68	
